module.render:
const def = (v, d) => (v === undefined || v === '') ? d : v;
const clean = (v) => String(v || '').replace(/[<>"']/g, '').trim();

// 8 anchor points on the box edges, as [x%, y%].
const ANCH = { tl:[0,0], tc:[50,0], tr:[100,0], lc:[0,50], rc:[100,50], bl:[0,100], bc:[50,100], br:[100,100] };
const sA = ANCH[clean(args.start)] || ANCH.lc;
const eA = ANCH[clean(args.end)] || ANCH.rc;

const color = clean(args.color) || 'currentColor';
const sw = Math.max(0.1, parseFloat(def(args.thickness, '2')) || 2);
const width = clean(def(args.width, '100%')) || '100%';
const height = clean(def(args.height, '60px')) || '60px';
const op = Math.max(0, Math.min(1, parseFloat(def(args.opacity, '1'))));
const opacity = Number.isFinite(op) ? op : 1;
const cs = Math.max(0.3, Math.min(4, parseFloat(def(args.capscale, '1')) || 1));
const ms = (n) => +(n * cs).toFixed(2);
const al = String(def(args.align, 'left')).toLowerCase();
const mx = al === 'center' ? '0.5rem auto' : al === 'right' ? '0.5rem 0 0.5rem auto' : '0.5rem 0';

const dashMap = {
  solid: '',
  dashed: (sw * 3) + ',' + (sw * 2),
  dotted: '0.01,' + (sw * 2),
  dashdot: (sw * 3) + ',' + (sw * 1.6) + ',0.01,' + (sw * 1.6)
};
const dash = dashMap[clean(args.linestyle)] || '';

const startShape = clean(args.startshape) || 'none';
const endShape = clean(args.endshape) || 'none';

// Unique marker ids per instance (avoid <defs> id collisions across lines).
const seq = (typeof window !== 'undefined') ? (window.__mdpLineSeq = (window.__mdpLineSeq || 0) + 1) : 1;
const uid = 'mdpln' + seq;

// A marker pointing forward (right); orient="auto-start-reverse" makes the
// start marker flip outward. markerUnits="strokeWidth" -> scales with thickness.
const marker = (id, shape) => {
  if (shape === 'none') return '';
  const head = '<marker id="' + id + '" markerUnits="strokeWidth" orient="auto-start-reverse" ';
  if (shape === 'arrow')      return head + 'viewBox="0 0 12 12" refX="10" refY="6" markerWidth="' + ms(8) + '" markerHeight="' + ms(8) + '"><path d="M1,1 L11,6 L1,11 z" fill="' + color + '"/></marker>';
  if (shape === 'triangle')   return head + 'viewBox="0 0 12 12" refX="10" refY="6" markerWidth="' + ms(7) + '" markerHeight="' + ms(9) + '"><path d="M2,1 L11,6 L2,11 z" fill="' + color + '"/></marker>';
  if (shape === 'arrow-open') return head + 'viewBox="0 0 12 12" refX="9" refY="6" markerWidth="' + ms(9) + '" markerHeight="' + ms(9) + '"><path d="M2,2 L10,6 L2,10" fill="none" stroke="' + color + '" stroke-width="1.6"/></marker>';
  if (shape === 'bar')        return head + 'viewBox="0 0 12 12" refX="6" refY="6" markerWidth="' + ms(5) + '" markerHeight="' + ms(9) + '"><path d="M6,1 L6,11" stroke="' + color + '" stroke-width="2"/></marker>';
  if (shape === 'dot')        return head + 'viewBox="0 0 12 12" refX="6" refY="6" markerWidth="' + ms(6) + '" markerHeight="' + ms(6) + '"><circle cx="6" cy="6" r="4" fill="' + color + '"/></marker>';
  if (shape === 'round')      return head + 'viewBox="0 0 12 12" refX="6" refY="6" markerWidth="' + ms(5) + '" markerHeight="' + ms(5) + '"><circle cx="6" cy="6" r="2.6" fill="' + color + '"/></marker>';
  if (shape === 'circle')     return head + 'viewBox="0 0 12 12" refX="6" refY="6" markerWidth="' + ms(6) + '" markerHeight="' + ms(6) + '"><circle cx="6" cy="6" r="3.6" fill="none" stroke="' + color + '" stroke-width="1.4"/></marker>';
  if (shape === 'square')     return head + 'viewBox="0 0 12 12" refX="6" refY="6" markerWidth="' + ms(6) + '" markerHeight="' + ms(6) + '"><rect x="2.5" y="2.5" width="7" height="7" fill="' + color + '"/></marker>';
  if (shape === 'diamond')    return head + 'viewBox="0 0 12 12" refX="6" refY="6" markerWidth="' + ms(7) + '" markerHeight="' + ms(7) + '"><path d="M6,1 L11,6 L6,11 L1,6 z" fill="' + color + '"/></marker>';
  return '';
};

const sId = uid + '-s', eId = uid + '-e';
const defs = '<defs>' + marker(sId, startShape) + marker(eId, endShape) + '</defs>';
const mStart = startShape !== 'none' ? ' marker-start="url(#' + sId + ')"' : '';
const mEnd = endShape !== 'none' ? ' marker-end="url(#' + eId + ')"' : '';
const dashAttr = dash ? ' stroke-dasharray="' + dash + '"' : '';

const svg = '<svg class="mdp-mod-line-svg" width="100%" height="100%" style="overflow:visible; display:block; opacity:' + opacity + ';">'
  + defs
  + '<line x1="' + sA[0] + '%" y1="' + sA[1] + '%" x2="' + eA[0] + '%" y2="' + eA[1] + '%" '
  + 'stroke="' + color + '" stroke-width="' + sw + '" fill="none" stroke-linecap="round"'
  + dashAttr + mStart + mEnd + '/>'
  + '</svg>';

return '\n\n<div class="mdp-mod-line" style="width:' + width + '; height:' + height + '; margin:' + mx + ';">' + svg + '</div>\n\n';
